          {
            "t": "i32",
            "v": 90
          }
        ]
      },
      "expected_output": "result=         Z\nlength=10\n"
    },
    {
      "input": {
        "format": "%*u",
        "args": [
          {
            "t": "i32",
            "v": -6
          },
          {
            "t": "u32",
            "v": 5
          }
        ]
      },
      "expected_output": "result=5     \nlength=6\n"
    }
  ]
}
